PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE inward (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    inward_no TEXT NOT NULL UNIQUE,
    means TEXT NOT NULL,
    particulars_from_whom TEXT NOT NULL,
    subject TEXT NOT NULL,
    assigned_to TEXT,
    sign_receipt_datetime TEXT NOT NULL,
    file_reference TEXT DEFAULT '',
    assigned_team TEXT,
    assigned_to_email TEXT,
    assignment_instructions TEXT DEFAULT '',
    assignment_date TEXT,
    assignment_status TEXT DEFAULT 'Unassigned',
    due_date TEXT,
    completion_date TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE outward (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    outward_no TEXT NOT NULL UNIQUE,
    means TEXT NOT NULL,
    to_whom TEXT NOT NULL,
    subject TEXT NOT NULL,
    sent_by TEXT NOT NULL,
    sign_receipt_datetime TEXT NOT NULL,
    case_closed INTEGER DEFAULT 0,
    file_reference TEXT DEFAULT '',
    postal_tariff REAL DEFAULT 0,
    due_date TEXT,
    linked_inward_id INTEGER,
    created_by_team TEXT NOT NULL,
    team_member_email TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now')), ack_rec TEXT, cross_no TEXT, receipt_no TEXT, remarks TEXT,
    FOREIGN KEY (linked_inward_id) REFERENCES inward(id)
);
CREATE TABLE notifications (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_email TEXT NOT NULL,
    title TEXT NOT NULL,
    message TEXT,
    type TEXT DEFAULT 'info', -- info, warning, success, error
    related_type TEXT, -- inward, outward, assignment
    related_id INTEGER,
    is_read INTEGER DEFAULT 0,
    created_at TEXT DEFAULT (datetime('now')),
    read_at TEXT
);
CREATE TABLE messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    from_email TEXT NOT NULL,
    to_email TEXT NOT NULL,
    subject TEXT NOT NULL,
    body TEXT,
    related_type TEXT, -- inward, outward
    related_id INTEGER,
    is_read INTEGER DEFAULT 0,
    created_at TEXT DEFAULT (datetime('now')),
    read_at TEXT
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_inward_status ON inward(assignment_status);
CREATE INDEX idx_inward_team ON inward(assigned_team);
CREATE INDEX idx_outward_team ON outward(created_by_team);
CREATE INDEX idx_outward_linked ON outward(linked_inward_id);
CREATE INDEX idx_inward_assigned_team ON inward(assigned_team);
CREATE INDEX idx_outward_created_by_team ON outward(created_by_team);
CREATE INDEX idx_notifications_user_email ON notifications(user_email);
CREATE INDEX idx_notifications_is_read ON notifications(is_read);
CREATE INDEX idx_messages_to_email ON messages(to_email);
CREATE INDEX idx_messages_is_read ON messages(is_read);
